        <div className="empty-state">
          <div className="es-icon">🚢</div>
          <div className="es-text">Upload a hull image and click <strong>Analyze Hull</strong> to get started.</div>
        </div>
      )}
    </>
  );
}

/* ═══════════════════════════════════════════════════
